import Vue from 'vue'
import Vuex from 'vuex'
import BV from './modules/bimview'
import CP from './modules/capacity'
import RS from './modules/rdfStore'

Vue.use(Vuex)
const N3 = require('n3');

Vue.filter('kb', val => {
  return Math.floor(val/1024);  
});

const serverURL = 'trinpod.us';
//const serverURL = 'trinpod.eu';
//const serverURL = 'stage.graphmetrix.net';

const testNum = 7;

const store = new Vuex.Store({
  state: {
    sensors: [],
    n3store: new N3.Store(),
    devMode: false,
    blankExisted: false,
    customers: [],
    blankNodeIndex: 1,
    blankNodeString: "",
    isLoggedIn: false,
    webId: "",
    loggedInName: "",
    loggedInInitials: "",
    loginExpire: "",
    currentBuildingTag: "",
    tasks: [],
    ministryURI: "https://helsenorge"+testNum+'.'+serverURL,
    serverURL: serverURL,
    testNum: testNum,
    whatToDoVisible: false,
  },


  modules: {
    bv: BV,
    rs: RS,
    cp: CP,
  },

  // Mutations are functions that affect the State
  mutations: {
    blankNodeIncrement(state, qty) {
      if (!qty) {
        qty = 1
      }
      var index = state.blankNodeIndex;
      var idx = index + qty;
      state.blankNodeIndex = idx;
      state.blankNodeString = "_:t" + idx;
      //console.log("blankNodeIncrement", idx);
    },
  },
  // Action are functions that call Mutations
  actions: {


  },
  computed: {

  },
  methods: {

  }

});

export default store
