bmu.checkIfPointInsideMesh = function(point, mesh){
  const buildingbox = store.state.bv.scene.getObjectByName("buildingbox");
  const direction = new Vector3(1, 1, 1);
  store.state.bv.raycaster.set(point.applyMatrix4(buildingbox.matrixWorld), direction);
  let intersects = store.state.bv.raycaster.intersectObject(mesh, true);
  try{
    if (intersects.length && direction.dot(intersects[0].face.normal) > 0) {
      //console.log(`Point is in object`);
      return true;
    } else {
      //console.log(`Point is out of object`);
      return false;
    }
  } catch(error){}
}

bmu.raycastRoomsFromPoint = function(point, direction){
  store.state.bv.raycaster.set(point, direction);
  let intersects = store.state.bv.raycaster.intersectObject(mesh, true);
  const intersectNames = [];
  intersects.forEach(intersect => {
    if(!intersectNames.includes(intersect.name)) intersectNames.push(intersect.name);
  });
  return intersectNames;
}

bmu.raycastUsingVector = function(point, direction){
  const buildingbox = store.state.bv.scene.getObjectByName("buildingbox");
  buildingbox.updateMatrixWorld();
  store.state.bv.raycaster.set(point.applyMatrix4(buildingbox.matrixWorld), direction.applyMatrix4(buildingbox.matrixWorld));
  let intersects = store.state.bv.raycaster.intersectObjects( buildingbox.children, true );
  const buildingMatrix = buildingbox.matrixWorld.invert();
  for(let i=0; i<intersects.length-1; i++){
    intersects[i].point.applyMatrix4(buildingMatrix);
  }
  return intersects;
}

