bmu.trinagulateAndCalculateArea = function(polyline){
  const polyArray = bmu.convertPolylineToPolyarray(polyline);
  // Create points from polyline
  var aPoints = [];
  if(polyArray.length >= 10){
    while (polyArray.length > 1) {
      const polyXYZ = polyArray.splice(0, 3); // Puts 3 first object from array in polyXYZ, and removes from polyArray
      const x = (polyXYZ[0]);
      const y = (polyXYZ[1]);
      var arr = [x, y]; // Will be mirrored without geoL-y
      aPoints.push(arr);
    }
  }

  // Start triangulate
  var poly2tri = require('poly2tri');
  var shape = [];
  for(var i=0; i<aPoints.length-1; ++i) {
    shape.push(new poly2tri.Point(aPoints[i][0], aPoints[i][1]));
  }
  var swctx = new poly2tri.SweepContext(shape);
  var triangles = swctx.triangulate();

  // Calculate area of triangles
  let totalArea = 0;
  for(var i=0; i<triangles.triangles_.length; ++i) {
    let v1 = new Vector3(triangles.triangles_[i].points_[0].x, triangles.triangles_[i].points_[0].y, 0);
    let v2 = new Vector3(triangles.triangles_[i].points_[1].x, triangles.triangles_[i].points_[1].y, 0);  
    let v3 = new Vector3(triangles.triangles_[i].points_[2].x, triangles.triangles_[i].points_[2].y, 0);  
    const currentTriangle = new Triangle(v1, v2, v3);
    totalArea = totalArea+currentTriangle.getArea();
  }
  console.log("Total area: "+totalArea);
  
  return totalArea;
}

bmu.createPlaceMarker = function(pos, color=0xff0000, removePrevious){
    const buildingbox = store.state.bv.scene.getObjectByName("buildingbox");
    const previousPlacemarker = store.state.bv.scene.getObjectByName("placemarker");
    if(previousPlacemarker && removePrevious){
      buildingbox.remove(previousPlacemarker);
    }
    const material = new MeshLambertMaterial({
        transparent: true,
        opacity: 0.6,
        color: color,
        depthTest: true
    });
    const geometry = new BoxGeometry(0.08, 10.0, 0.08);
    geometry.translate(pos.x,pos.y,pos.z);
    const marker = new Mesh(geometry, material);
    marker.name = "placemarker";
    buildingbox.add(marker);
    return marker;
}

