bmu.draw2dspace = function(myPolyArray, polyPos, color=0xbbbbdd, name=""){
  const buildingbox = store.state.bv.scene.getObjectByName("buildingbox");
  const material = new MeshLambertMaterial({color: color, transparent:true, opacity:0.3});
  let polyShape = new Shape();
  let polyArray = [];
  myPolyArray.forEach(point => {polyArray.push(point)});
  //console.log(polyArray)
  let i = 0;
  while (polyArray.length > 1) {
    const polyXYZ = polyArray.splice(0, 3); // Puts 3 first object from array in polyXYZ, and removes from polyArray
    const x = (polyXYZ[0]);
    const y = (polyXYZ[1]);
    if(i == 0){
      polyShape.moveTo( (-x+polyPos.y), (-y-polyPos.x), polyPos.z );
      i = i+1;
    } else {
      polyShape.lineTo( (-x+polyPos.y), (-y-polyPos.x), polyPos.z );
    }
  }
  polyShape.autoClose = true;
  const extrudeSettings = { extrudePath: new LineCurve3( new Vector3( 0, polyPos.z, 0 ), new Vector3( 0, polyPos.z+0.5, 0 ) ) };
  const polyGeometry = new ExtrudeGeometry( polyShape, extrudeSettings );
  const polyMesh = new Mesh( polyGeometry, material ) ;
  polyMesh.name = name;
  buildingbox.add(polyMesh);
}

bmu.angleThreeVectors = function( vec1, vecAngle, vec2) {
  let angle = 0;

	if ( vec1.x === 0 && vec1.y === 0 && vec1.z === 0 ) return 0;
	if ( vec2.x === 0 && vec2.y === 0 && vec2.z === 0 ) return 0;

	vec1.sub( vecAngle );
	vec2.sub( vecAngle );

	angle = vec1.angleTo( vec2 );

	vec1.add( vecAngle );
	vec2.add( vecAngle );

	return angle ;
}

