<template>
  <div class="feedback">
    <v-btn
          style="position: absolute; z-index: 3; top: 28px; right: 8px;"
          color="#3577cb"
          class="white--text"
          @click="toggleViews"
        >
        <v-icon>mdi-arrow-split-vertical</v-icon>
    </v-btn>
    <Split    
    ref="splitter"
    @onDragStart="dragStart"
    @onDragEnd="dragEnd"
    :gutterSize="10"
    :snapOffset="200"
    style="height: 95vh">
    	<SplitArea ref="split1" :size="current_splitter_state[0]" :min-size="350">
        <Capacity msg="Show capacity form" />
      </SplitArea>
      <SplitArea ref="split2" :size="current_splitter_state[1]" :min-size="0">
        <BIMviewer msg="Show bimviewer form" />
      </SplitArea>
    </Split>
  </div>
</template>

<script>
// @ is an alias to /src
import Capacity from '../components/Capacity.vue'
import BIMviewer from '../components/BIMviewer.vue'
import { Split, SplitArea} from 'vue-split-panel'
import "vuetify/dist/vuetify.min.css";
import { mapMutations } from "vuex";
import store from '../store';

export default {
  name: 'CapacityV',
  components: {
    Capacity,
    BIMviewer,
    Split,
    SplitArea
  },
  data: function() {
    return {
      splitter_collapsed: false,
      current_splitter_state: [30, 70],
      default_splitter_state: [30, 70],
      last_splitter_state: [30, 70],
      bimVisible: true,
    };
  },
  mounted: function() {
    this.current_splitter_state = [31, 70];
  },
  methods: {
    ...mapMutations('bv', ["RESIZE"]),
    preDragStart: function(evt) {},
    dragStart: function(initialSize) {
      this.last_splitter_state = initialSize;
    },
    dragEnd: function(size) {
      console.log("dragEnd");
      console.log("current_splitter_state", this.current_splitter_state);
      console.log("last_splitter_state", this.last_splitter_state);
      if (
        this.current_splitter_state[0] === this.last_splitter_state[0] &&
        this.current_splitter_state[1] === this.last_splitter_state[1]
      ) {
        this.toggleCollapseSplitter(true, size);
      }
      if (
        this.current_splitter_state[0] === 99 &&
        this.current_splitter_state[1] === 1
      ) {
        this.toggleCollapseSplitter(false, size);
      }
      if (
        this.current_splitter_state[0] === 1 &&
        this.current_splitter_state[1] === 99
      ) {
        this.toggleCollapseSplitter(false, size);
      }
      if(this.current_splitter_state[0] < 30){
        this.last_splitter_state = this.current_splitter_state;
        this.splitter_collapsed = true;
        this.current_splitter_state = [30, 70]; // Can set to 1, 99 if want to colapse when dragging past limit
      }
      this.updateCanvasSize();
    },
    toggleCollapseSplitter: function(flag, size) {
      console.log("splitter collapsed", flag);
      if (!flag) {
        this.current_splitter_state = this.last_splitter_state;
      } else {
        this.last_splitter_state = size;
        this.current_splitter_state = [99, 1];
      }
      this.updateCanvasSize();
    },
    updateCanvasSize(){
      const width = (this.current_splitter_state[1]/100)*window.innerWidth;
      const height = 0.95*window.innerHeight;
      this.RESIZE({
        width: width,
        height: height
      });
    },
    toggleViews(){
      if(this.current_splitter_state[0] == 99){
        this.last_splitter_state = this.current_splitter_state;
        this.splitter_collapsed = true;
        this.current_splitter_state = [1, 99];
        this.bimVisible = true;
      } else if(this.current_splitter_state[0] == 1) {
        this.last_splitter_state = this.current_splitter_state;
        this.splitter_collapsed = false;
        this.current_splitter_state = [40, 60];
        this.bimVisible = true;
      } else {
        this.last_splitter_state = this.current_splitter_state;
        this.splitter_collapsed = true;
        this.current_splitter_state = [99, 1];
        this.bimVisible = false;
      }
      this.updateCanvasSize();
    },
    windowResize(){
      console.log("window resize!!!!!!!!")
      if(window.innerWidth <= 1000){
        this.last_splitter_state = this.current_splitter_state;
        this.splitter_collapsed = true;
        this.current_splitter_state = [99, 1];
        this.bimVisible = false;
      } else {
        this.last_splitter_state = this.current_splitter_state;
        this.splitter_collapsed = false;
        this.current_splitter_state = [30, 70];
        this.bimVisible = true;
      }
      this.updateCanvasSize();
    }
  },
  mounted(){
    this.windowResize();
  },
  created() {
    window.addEventListener("resize", this.windowResize);
  },
  destroyed() {
    window.removeEventListener("resize", this.windowResize);
  }
}
</script>

