const ig = {}

//import { Math } from "Mathjs";
import { Vector2, Vector3 } from "three";

export default {
  ig: ig,
  name: 'ImplicitGeometry',
  methods: {
    v3abs(v3){
      // Makes absolute value of all components of the vector
      v3.x = Math.abs(v3.x);
      v3.y = Math.abs(v3.y);
      v3.z = Math.abs(v3.z);
      return v3;
    },
    v2abs(v2){
      // Makes absolute value of all components of the vector
      v2.x = Math.abs(v2.x);
      v2.y = Math.abs(v2.y);
      return v2;
    },
    v3max(v1, v2){
      // Finds max values of each of each leg in vector
      v1.x = Math.max(v1.x, v2.x);
      v1.y = Math.max(v1.y, v2.y);
      v1.z = Math.max(v1.z, v2.z);
      return v1;
    },
    v2max(v1, v2){
      // Finds max values of each of each leg in vector
      v1.x = Math.max(v1.x, v2.x);
      v1.y = Math.max(v1.y, v2.y);
      return v1;
    },
    v2min(v1, v2){
      // Finds min values of each of each leg in vector
      v1.x = Math.min(v1.x, v2.x);
      v1.y = Math.min(v1.y, v2.y);
      return v1;
    },
    v2max0(v1){
      v1.x = Math.max(v1.x, 0);
      v1.y = Math.max(v1.y, 0);
      return v1;
    },
    v2length(v1, v2){
      // Calculates the straight-line length between two vectors
      return Math.sqrt((v1.x-v2.x)*(v1.x-v2.x)+(v1.y-v2.y)*(v1.y-v2.y));
    },
    v2length0(v1){
      return Math.sqrt(v1.x*v1.x+v1.y*v1.y);
    },
    v2subtract(v1, v2){
      // Subtracts two vectors
      v1.x = v1.x-v2.x;
      v1.y = v1.y-v2.y;
      return v1;
    },
    v3subtract(v1, v2){
      // Subtracts two vectors
      v1.x = v1.x-v2.x;
      v1.y = v1.y-v2.y;
      v1.z = v1.z-v2.z;
      return v1;
    },
    v3length(v1, v2){
      // Calculates the straight-line length between two vectors
      return Math.sqrt((v1.x-v2.x)*(v1.x-v2.x)+(v1.y-v2.y)*(v1.y-v2.y)+(v1.z-v2.z)*(v1.z-v2.z));
    },
    v3length0(v1, v2){
      // Calculates the straight-line length between two vectors
      return Math.sqrt((v1.x)*(v1.x)+(v1.y)*(v1.y)+(v1.z)*(v1.z));
    },
    clamp(num, min, max){
      return Math.min(Math.max(num, min), max);
    },
    v2scale(v1, num) {
      v1.x = v1.x*num;
      v1.y = v1.y*num;
      return v1;
    },
    v2multiply(v1, v2) {
      v1.x = v1.x*v2.x;
      v1.y = v1.y*v2.y;
      return v1;
    },
    v3scale(v1, num) {
      v1.x = v1.x*num;
      v1.y = v1.y*num;
      v1.z = v1.z*num;
      return v1;
    },
    dot(v1, v2) {
      return v1.x*v2.x+v1.y*v2.y;
    },
    opExtrussion(p, sdf, h)
    {
        const w = {x:sdf, y:Math.abs(p.z)-h};
        return Math.min(Math.max(w.x,w.y),0.0) + this.v2length(this.v2max(w,{x:0, y:0}), {x:0, y:0});
    },
    nGon(n, p, r) {
      // these 2 lines can be precomputed
      let an = 6.2831853/n;
      let he = r * Math.tan(0.5 * an);

      // rotate to first sector
      p = {x:-p.y, y:-p.x}; // if you want the corner to be up
      let bn = an * Math.floor((Math.atan(p.y/p.x) + 0.5 * an) / an);
      let cs = {x:Math.cos(bn), y:Math.sin(bn)};
      //p = mat2(cs.x, -cs.y, cs.y, cs.x) * p;

      // side of polygon
      return this.v2length(this.v2subtract(p, {x:r, y:this.clamp(p.y, -he, he)}), {x:0, y:0}) * Math.sign(p.x-r);
    },
    sdSphere(p, s){
      return Math.sqrt(p.x*p.x + p.y*p.y + p.z*p.z)-s;
    },
    sdSphereCut(p, ox, oy, oz, r){
      return ((p.x*p.x)-(ox*ox)) + ((p.y*p.y)-(oy*oy)) + ((p.z*p.z)-(oz*oz))-r;
    },
    sdBox(p, b){
      let absP = this.v3abs(p);
      let q = this.v3subtract(absP, b);
      return this.v3length(this.v3max(q, {x:0, y:0, z:0}), {x:0, y:0, z:0}) + Math.min(Math.max(q.x,Math.max(q.y, q.z)),0.0);
    },
    sdBoxLWH(x, y, z, length, width, height){
      const p = {x:x, y:y, z:z};
      const b = {x:length, y:width, z:height};

      const absP = this.v3abs(p);
      const q = this.v3subtract(absP, b);
      return this.v3length(this.v3max(q, {x:0, y:0, z:0}), {x:0, y:0, z:0}) + Math.min(Math.max(q.x,Math.max(q.y, q.z)),0.0);
    },
    impBox(x, y, z, length, width, height){
      const p = {x:x, y:y, z:z};
      const b = {x:length, y:width, z:height};

      const absP = this.v3abs(p);
      const q = this.v3subtract(absP, b);
      return this.v3length0(this.v3max(q, {x:0, y:0, z:0})) + Math.min(Math.max(q.x,Math.max(q.y, q.z)),0.0);
    },
    sdTriPrism(p, width, length){
      const h = {x:width, y:length};
      const q = this.v3abs(p);
      return Math.max(q.z-h.y,Math.max(q.x*0.866025+p.y*0.5,-p.y)-h.x*0.5);
    },
    sdCone(p, c) { // Made out from infinite cone
      const q = { x:this.v2length({x:p.x, y:p.z}, {x:0, y:0}), y:-p.y };
      const d = this.v2length(  this.v2subtract(q, this.v2scale(c, Math.max(this.dot(q,c), 0.0)) ), {x:0, y:0});
      return d * ((q.x*c.y-q.y*c.x<0.0)?-1.0:1.0);
    },
    sdAirpod(p, c) { // Made out from infinite cone
      const q = { x:this.v2length({x:p.x, y:p.z}, {x:0, y:0}), y:-p.y };
      const d = this.v2length(  this.v2subtract(q, this.v2scale(c, Math.max(this.dot(q,c), 0.0)) ), {x:0, y:0});
      return Math.min(d * ((q.x*c.y-q.y*c.x<0.0)?-1.0:1.0), Math.sqrt(p.x*p.x + p.y*p.y + p.z*p.z)-0.6);
    },
    sdRoundedCone(p, c) { // Made out from infinite cone
      const q = { x:this.v2length({x:p.x, y:p.z}, {x:0, y:0}), y:-p.y };
      const d = this.v2length(  this.v2subtract(q, this.v2scale(c, Math.max(this.dot(q,c), 0.0)) ), {x:0, y:0});
      return Math.min(d * ((q.x*c.y-q.y*c.x<0.0)?-1.0:1.0), Math.sqrt(p.x*p.x + p.y*p.y + p.z*p.z)-0.9);
    },
    espenTrekant(p){
      return this.v2length0({x:p.x, y:p.y}) * p.y;
    },
    sdTriangle(p, p0, p1, p2){ // 2d triangle with incoming corner points
      const e0 = this.v2subtract(p1, p0); //vec2 e0 = p1-p0
      const e1 = this.v2subtract(p2, p1); //vec2 e1 = p2-p1
      const e2 = this.v2subtract(p0, p2); //vec2 e2 = p0-p2
      const v0 = this.v2subtract(p, p0); //vec2 v0 = p -p0
      const v1 = this.v2subtract(p, p1); //vec2 v1 = p -p1
      const v2 = this.v2subtract(p, p2); //vec2 v2 = p -p2
      const pq0 = this.v2subtract(v0, this.v2scale(e0, this.clamp( this.dot(v0,e0)/this.dot(e0,e0), 0.0, 1.0 ))); // vec2 pq0 = v0 - e0*clamp( dot(v0,e0)/dot(e0,e0), 0.0, 1.0 );
      const pq1 = this.v2subtract(v1, this.v2scale(e1, this.clamp( this.dot(v1,e1)/this.dot(e1,e1), 0.0, 1.0 ))); // vec2 pq1 = v1 - e1*clamp( dot(v1,e1)/dot(e1,e1), 0.0, 1.0 );
      const pq2 = this.v2subtract(v2, this.v2scale(e2, this.clamp( this.dot(v2,e2)/this.dot(e2,e2), 0.0, 1.0 ))); // vec2 pq2 = v2 - e2*clamp( dot(v2,e2)/dot(e2,e2), 0.0, 1.0 );
      const s = Math.sign( (e0.x*e2.y) - (e0.y*e2.x) ); // float s = sign( e0.x*e2.y - e0.y*e2.x );
      const d = this.v2min(this.v2min({x:this.dot(pq0,pq0), y:s*(v0.x*e0.y-v0.y*e0.x)},
                       {x:this.dot(pq1,pq1), y:s*(v1.x*e1.y-v1.y*e1.x)}),
                       {x:this.dot(pq2,pq2), y:s*(v2.x*e2.y-v2.y*e2.x)}); //vec2 d = min(min(vec2(dot(pq0,pq0), s*(v0.x*e0.y-v0.y*e0.x)), vec2(dot(pq1,pq1), s*(v1.x*e1.y-v1.y*e1.x))), vec2(dot(pq2,pq2), s*(v2.x*e2.y-v2.y*e2.x)));
      return -Math.sqrt(d.x) * Math.sign(d.y); // return -sqrt(d.x)*sign(d.y);
    },
    signedDistanceToTriangle( p, p0, p1, p2 ) {

        const edge0X = p1.x - p0.x;
        const edge0Y = p1.y - p0.y;
        const edge1X = p2.x - p1.x;
        const edge1Y = p2.y - p1.y;
        const edge2X = p0.x - p2.x;
        const edge2Y = p0.y - p2.y;

        const v0X = p.x - p0.x;
        const v0Y = p.y - p0.y;
        const v1X = p.x - p1.x;
        const v1Y = p.y - p1.y;
        const v2X = p.x - p2.x;
        const v2Y = p.y - p2.y;

        const pq0X = v0X - edge0X * this.clamp( this.dot( v0X, edge0X ) / this.dot( edge0X, edge0X ), 0, 1 );
        const pq0Y = v0Y - edge0Y * this.clamp( this.dot( v0Y, edge0Y ) / this.dot( edge0Y, edge0Y ), 0, 1 );
        const pq1X = v1X - edge1X * this.clamp( this.dot( v1X, edge1X ) / this.dot( edge1X, edge1X ), 0, 1 );
        const pq1Y = v1Y - edge1Y * this.clamp( this.dot( v1Y, edge1Y ) / this.dot( edge1Y, edge1Y ), 0, 1 );
        const pq2X = v2X - edge2X * this.clamp( this.dot( v2X, edge2X ) / this.dot( edge2X, edge2X ), 0, 1 );
        const pq2Y = v2Y - edge2Y * this.clamp( this.dot( v2Y, edge2Y ) / this.dot( edge2Y, edge2Y ), 0, 1 );

        const s = Math.sign( edge0X * edge2Y - edge0Y * edge2X );

        const dotPQ0X = this.dot( pq0X, pq0X );
        const dotPQ0Y = this.dot( pq0Y, pq0Y );
        const dotPQ1X = this.dot( pq1X, pq1X );
        const dotPQ1Y = this.dot( pq1Y, pq1Y );
        const dotPQ2X = this.dot( pq2X, pq2X );
        const dotPQ2Y = this.dot( pq2Y, pq2Y );

        const s0 = s * ( v0X * edge0Y - v0Y * edge0X );
        const s1 = s * ( v1X * edge1Y - v1Y * edge1X );
        const s2 = s * ( v2X * edge2Y - v2Y * edge2X );

        const dX = Math.min( Math.min( dotPQ0X, s0, dotPQ1X, s1 ), dotPQ2X, s2 );
        const dY = Math.min( Math.min( dotPQ0Y, s0, dotPQ1Y, s1 ), dotPQ2Y, s2 );

        return -Math.sqrt( dX ) * Math.sign( dY );

    },
    espenTrekantExtrude(p, h){
      const d = this.v2length0({x:p.x, y:p.y}) * p.y;
      const w = {x:d, y:Math.abs(p.z)-h};
      const extrude = Math.max(Math.max(w.x,w.y),0.0) + this.v2length0(this.v2max0(w));
      return d;
    },
    toPrism(d2d, v, size) {
      let d = {x:d2d, y:(Math.abs(v)-0.5*size)};
      return this.v2length(this.v2max(d, {x:0, y:0}), {x:0, y:0}) + Math.min(Math.max(d.x, d.y), 0.0);
    },
    nPrism(p, n, r, depth){
      let d = this.nGon(n, {x:p.x, y:p.z}, r);
      return this.toPrism(d, p.y, depth);
    },
    sdRoof(p, width, length){
      const h = {x:width, y:length};
      const q = this.v3abs(p);
      if (p.y>=0.25){
        return Math.max(q.z-h.y,Math.max(q.x*0.866025+p.y*0.5,-p.y)-h.x*0.5);
      } else {
        return 0;
      }
    },
    sdOctahedron(p, s){
      let absP = this.v3abs(p);
      return (absP.x+absP.y+absP.z-s)*0.57735027;
    },
  }
};
