const r = {};

const $rdf = require('rdflib');
import store from '../store';

r.searchAndGetURIs = async function(conceptName){
    let uri = 'https://helsenorge'+store.state.testNum+'.'+ store.state.serverURL +'/search/'+encodeURIComponent(conceptName);
    try {
      let res = await window.solid.session.fetch(
        uri, {
          method: "GET",
          credentials: "include",
          headers: {
            "Accept": "text/turtle"
          },
      }).then(res => res.text());
      console.log(res);
      $rdf.parse(res, store.state.rs.rdfStore, uri, 'text/turtle');
      return res;
    } catch (error) {
      console.log(error);
      console.log("Search failed");
    }
  }

export default r;