    async getRoomZonesOnEachSideOfDoor(modelID, doorID, location){
      const debugF = false;
      const props = await ifcLoader.ifcManager.getItemProperties(modelID, doorID);
      const doorWidth = props.OverallWidth.value;
      const doorCenterDistance = doorWidth/1600;
      //const doorCenterDistance = 2.7;
      const loc = location.clone();
      loc.y = loc.y+0.2; // Buffer to make sure rays hit
      if(debugF) this.createPlaceMarker(loc, 0xFF0000);

      const firstOffsetPoint = new Vector3(doorCenterDistance, 0, 0); // Can change the number value to change radius of circle
      const firstPointOnCircle = loc.clone().add(firstOffsetPoint);
      const foundRooms = [];
      const direction = v.v3subtract(loc, firstPointOnCircle); // Creating vector pointing to center of door
      if(debugF) bmu.createVisibleVector(firstPointOnCircle, direction, 0xFF0000);
      if(debugF) this.createPlaceMarker(firstPointOnCircle.clone(), 0x00FF00, false);
      
      // Finding the intersects for the first point to circle
      const intersects = bmu.raycastUsingVector(firstPointOnCircle, direction);
      if(debugF) bmu.createVisibleVector(firstPointOnCircle, direction, 0xFF0000);
      intersects.forEach(inters => {
        if(inters.distance <= (doorCenterDistance*2)) {
          const distToLocation = loc.clone().distanceTo(inters.point.clone()); // Some points are found far from location, so have to do check.
          if(distToLocation <= (doorCenterDistance*2)){
            const roomname = inters.object.name;
            if(debugF) this.createPlaceMarker(inters.point, 0x0066FF, false); // For verifying where ray hits
            if(debugF) console.log("Room name: "+roomname+" Distance: "+inters.distance);
            if(!foundRooms.includes(roomname) && roomname!="" &&  roomname!="placemarker") foundRooms.push(roomname);
          }
        }
      });
    
      // Do room checks for each 45 degrees while rotating around door
      const axis = new Vector3(0, 1, 0);
      const angle = Math.PI/3;
      for(let i=0; i<=4; i++){
        const currentCheckPoint = loc.clone().add(firstOffsetPoint.applyAxisAngle(axis, angle));
        if(debugF) this.createPlaceMarker(currentCheckPoint, 0x0000FF, false);
        const direction = v.v3subtract(loc, currentCheckPoint).normalize(); // Creating vector pointing to center of door
        if(debugF) bmu.createVisibleVector(currentCheckPoint, direction, 0xFF9900);
        const intersects2 = bmu.raycastUsingVector(currentCheckPoint, direction);
        intersects2.forEach(inters => {
          if(inters.distance <= (doorCenterDistance*2)) {
            const distToLocation = loc.distanceTo(inters.point);
            if(distToLocation <= (doorCenterDistance*2)){
              const roomname = inters.object.name;
              if(debugF) this.createPlaceMarker(inters.point, 0x0066FF, false); // For verifying where ray hits
              if(debugF) console.log("Room name: "+roomname+" Distance: "+inters.distance);
              if(!foundRooms.includes(roomname) && roomname!="" && roomname!="placemarker") foundRooms.push(roomname);
            }
          }
        });
      }
      // Debugging +++++
      //bmu.panToFocusObject(location.x, location.z);
      //alert("Moved to point.");
      // Debugging -----
      return foundRooms;
    },
