    async getIFCElementLocationTranslated(expressID, modelID){
        const spaceProperties = await ifcLoader.ifcManager.getItemProperties(modelID, expressID);
        const positionProperties = await ifcLoader.ifcManager.getItemProperties(modelID, spaceProperties.ObjectPlacement.value);
        console.log("objectplacement:")
        console.log(positionProperties);
        const relativePlacement = await ifcLoader.ifcManager.getItemProperties(modelID, positionProperties.RelativePlacement.value);
        const PlacementRelTo = await ifcLoader.ifcManager.getItemProperties(modelID, positionProperties.PlacementRelTo.value);
        console.log("PlacementRelTo:")
        console.log(PlacementRelTo);
        const relToRelativePlacement = await ifcLoader.ifcManager.getItemProperties(modelID, PlacementRelTo.RelativePlacement.value);
        const relToLocation = await ifcLoader.ifcManager.getItemProperties(modelID, relToRelativePlacement.Location.value);
        const relTocoordinates = relToLocation.Coordinates;
        const location = await ifcLoader.ifcManager.getItemProperties(modelID, relativePlacement.Location.value);
        const ifcAxis = await ifcLoader.ifcManager.getItemProperties(modelID, relativePlacement.Axis.value);
        const refDirection = await ifcLoader.ifcManager.getItemProperties(modelID, relativePlacement.RefDirection.value);
        const directionRatios = refDirection.DirectionRatios;
        const axisDirectionRatios = ifcAxis.DirectionRatios;
        const coordinates = location.Coordinates;
        var point1 = (coordinates[0].value/100);
        var point2 = (coordinates[1].value/100);
        console.log("Coordinates:")
        console.log(coordinates);
        // Functionality to find rotation START ---------------------
        const inRotation = { x:directionRatios[0].value, y:directionRatios[1].value, z:directionRatios[2].value };
        const inAxis = { x: axisDirectionRatios[0].value, y:axisDirectionRatios[1].value, z:axisDirectionRatios[2].value };
        const crossProduct = ifcu.v3cross(inRotation, inAxis);
        const myAxis = { x:0, y:-1, z:0 };

        var angle = ifcu.getAngleRadians(crossProduct.x, crossProduct.y, inRotation.x, inRotation.y);
        var angle2 = ifcu.getAngleRadians(inAxis.x, inAxis.y, myAxis.x, myAxis.y);
        angle = (angle2-angle)+(Math.PI/4);
        // Functionality to find rotation END ---------------------
        const rotatedPoints = ifcu.rotateRadians(0, 0, point1, point2, angle);
        point1 = rotatedPoints[0];
        point2 = rotatedPoints[1];
        return {x: point1, y: point2};
    },
